class Solution:
    def uniquePaths(self, m: int, n: int) -> int:
        f = [1] * n                  # f[j] = 到当前行第 j 列的路径数;第一行全为 1
        for _ in range(1, m):        # 逐行往下
            for j in range(1, n):
                f[j] += f[j - 1]     # 来自上方 f[j] + 来自左边 f[j-1]
        return f[-1]
